from flask import Flask, render_template, redirect, request
from flask_oidc import OpenIDConnect
from werkzeug.security import generate_password_hash

app = Flask(__name__)

app.config['SECRET_KEY'] = generate_password_hash('secret key', method='sha256')
app.config['OIDC_CLIENT_ID'] = 'your_client_id'
app.config['OIDC_CLIENT_SECRET'] = 'your_client_secret'
app.config['OIDC_REDIRECT_URI'] = 'your_redirect_uri'
app.config['OIDC_API_BASE_URL'] = 'your_api_base_url'
app.config['OIDC_SCOPE'] = 'openid'
app.config['OIDC_RESPONSE_TYPE'] = 'id_token'

oidc = OpenIDConnect(app)

@app.route('/')
def index():
    return render_template('index.html')

@app.route('/login')
def login():
    return redirect(oidc.authorize_url)

@app.route('/callback')
def callback():
    token_info = oidc.verify_token(request.args['id_token'])
    # Handle successful authentication here
    return render_template('dashboard.html', user=token_info)

if __name__ == '__main__':
    app.run(debug=True)